class PriorityQueue {
    constructor() {
        this.heap = [];
    }
    enqueue(value, ...rest) {
        const item = [value, ...rest];
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }
    dequeue() {
        if (this.heap.length === 0) return null;
        const result = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown(0);
        return result;
    }
    isEmpty() {
        return this.heap.length === 0;
    }
    heapifyUp(index) {
        while (index > 0) {
            const parent = Math.floor((index - 1) / 2);
            if (this.heap[index][0] < this.heap[parent][0]) {
                [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                index = parent;
            } else {
                break;
            }
        }
    }
    heapifyDown(index) {
        const n = this.heap.length;
        while (index < n) {
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            let smallest = index;
            if (left < n && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < n && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            } else {
                break;
            }
        }
    }
}

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const INF = Infinity;
    const dist = new Array(m).fill().map(() => new Array(n).fill().map(() => new Array(k+1).fill(INF)));
    dist[0][0][0] = 0;

    const pq = new PriorityQueue();
    pq.enqueue(0, 0, 0, 0);

    const dirs = [[0, 1], [1, 0]];

    while (!pq.isEmpty()) {
        const [cost, i, j, t] = pq.dequeue();

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (cost > dist[i][j][t]) {
            continue;
        }

        // Regular moves
        for (const [dx, dy] of dirs) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni < m && nj < n) {
